<?php namespace App\Services\KYC; use App\Models\KYC\KYCApplication; class KYCService { public function create($data) { return KYCApplication::create([...$data, 'application_number' => 'KYC-'.now()->format('YmdHis'), 'created_by' => auth()->id()]); } public function approve(KYCApplication $app) { $app->update(['status' => 'APPROVED', 'approved_by' => auth()->id(), 'approved_at' => now()]); } }
